const expect = require('chai').expect;
var pack = require('../package.json');
const {
    Range,
    INFINITE_DURATION,
    AnimDB
} = require('../' + pack.main);


describe('Main Test suite', () => {

    it('Load library', function () {
        expect(AnimDB).to.be.a('function');
    });

    it('Range', () => {
        let r = new Range(-3, 3);
        expect(r.distanceFrom(0)).to.equal(0);
        expect(r.distanceFrom(-3)).to.equal(0);
        expect(r.distanceFrom(3)).to.equal(0);
        expect(r.distanceFrom(-4)).to.equal(1);
        expect(r.distanceFrom(4)).to.equal(1);
        expect(r.limit(4)).to.equal(3);
        expect(r.limit(-4)).to.equal(-3);
        expect(r.limit(1)).to.equal(1);

        r = new Range(-3, INFINITE_DURATION);
        expect(r.distanceFrom(0)).to.equal(0);
        expect(r.distanceFrom(-4)).to.equal(1);
        expect(r.limit(4)).to.equal(4);
        expect(r.limit(-4)).to.equal(-3);
        expect(r.isUpperInfinite()).to.equal(true);
    });
});
